        const widget = document.getElementById('mainWidget');
        widget.classList.toggle('light-mode');
        // 保存偏好
        try {
            const isLight = widget.classList.contains('light-mode');
            localStorage.setItem('widget_theme', isLight ? 'light' : 'dark');
        } catch(e) {}
    }

    // 进度条更新逻辑
    function updateProgressBars() {
        const bars = document.querySelectorAll('.progress-bar');
        bars.forEach(bar => {
            const value = parseFloat(bar.getAttribute('data-value')) || 0;
            const max = parseFloat(bar.getAttribute('data-max')) || 100;
            const percentage = Math.min(Math.max((value / max) * 100, 0), 100);
            bar.style.width = percentage + '%';
        });
    }

    // 初始化执行
